import { useState, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { useData } from "../contexts/DataContext";
import { DELIVERY_STATUSES } from "../lib/mockData";
import { Button } from "../components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "../components/ui/dropdown-menu";
import { Dialog, DialogContent } from "../components/ui/dialog";
import {
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  CheckCircle2,
} from "lucide-react";
import { toast } from "sonner";

const PAGE_SIZE = 4;

export default function StatusPengiriman() {
  const { orders = [], setDeliveryStatus } = useData();
  const navigate = useNavigate();

  const [page, setPage] = useState(1);
  const [showSuccess, setShowSuccess] = useState(false);

  // pagination safe
  const totalPages = Math.max(1, Math.ceil(orders.length / PAGE_SIZE));

  const items = useMemo(() => {
    const start = (page - 1) * PAGE_SIZE;
    return orders.slice(start, start + PAGE_SIZE);
  }, [orders, page]);

  const startIndex = (page - 1) * PAGE_SIZE;

  const handleSave = () => {
    if (!orders.length) {
      toast.error("Tidak ada data untuk disimpan");
      return;
    }

    setShowSuccess(true);
    toast.success("Status pengiriman berhasil disimpan");
  };

  const handleStatusChange = (id, status) => {
    setDeliveryStatus(id, status);
  };

  return (
    <div className="max-w-[1200px]" data-testid="status-page">
      <h1 className="text-3xl font-extrabold text-gray-900">
        Status Pengiriman
      </h1>
      <p className="text-sm text-gray-500 mt-1 mb-8">
        Perbaharui Status Pengiriman
      </p>

      <div className="mpl-card overflow-hidden">
        {/* HEADER */}
        <div className="grid grid-cols-[1fr_1.3fr_1fr_1.5fr] gap-4 px-7 py-4 mpl-table-header bg-gray-50/60">
          <div>ID Pesanan</div>
          <div>Nama Pelanggan</div>
          <div>Tanggal</div>
          <div>Status</div>
        </div>

        {/* BODY */}
        <div className="divide-y divide-gray-100">
          {items.length === 0 ? (
            <div className="text-center py-10 text-gray-400 text-sm">
              Tidak ada data
            </div>
          ) : (
            items.map((o) => (
              <div
                key={o.id}
                className="grid grid-cols-[1fr_1.3fr_1fr_1.5fr] gap-4 px-7 py-5 items-center"
              >
                <div className="font-bold text-gray-900">#{o.id}</div>

                <div className="flex items-center gap-3">
                  <div
                    className={`w-8 h-8 rounded-full flex items-center justify-center text-[11px] font-bold ${o.avatarColor}`}
                  >
                    {o.initials}
                  </div>
                  <span className="text-sm text-gray-900">
                    {o.customer}
                  </span>
                </div>

                <div className="text-sm text-gray-700">
                  {o.date}
                </div>

                <div className="flex items-center gap-2">
                  <Button
                    onClick={() => navigate(`/invoice/${o.id}`)}
                    className="mpl-btn-primary h-8 px-3 text-[10px] rounded-md"
                  >
                    Upload
                  </Button>

                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <button className="bg-gray-100 hover:bg-gray-200 text-gray-700 h-8 px-3 text-[11px] rounded-md flex items-center gap-1.5 font-medium">
                        {o.deliveryStatus}
                        <ChevronDown className="w-3 h-3" />
                      </button>
                    </DropdownMenuTrigger>

                    <DropdownMenuContent align="end" className="w-48">
                      {DELIVERY_STATUSES.map((s) => (
                        <DropdownMenuItem
                          key={s}
                          onClick={() =>
                            handleStatusChange(o.id, s)
                          }
                          className="cursor-pointer"
                        >
                          {s}
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              </div>
            ))
          )}
        </div>

        {/* FOOTER */}
        <div className="flex items-center justify-between px-7 py-4 bg-gray-50/60 border-t border-gray-100">
          <div className="text-[11px] text-gray-400">
            Menampilkan {startIndex + 1}-
            {Math.min(startIndex + PAGE_SIZE, orders.length)} dari{" "}
            {orders.length}
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="w-8 h-8 border rounded-md disabled:opacity-40"
            >
              <ChevronLeft className="w-4 h-4 mx-auto" />
            </button>

            <button
              onClick={() =>
                setPage((p) => Math.min(totalPages, p + 1))
              }
              disabled={page === totalPages}
              className="w-8 h-8 border rounded-md disabled:opacity-40"
            >
              <ChevronRight className="w-4 h-4 mx-auto" />
            </button>
          </div>
        </div>
      </div>

      {/* SAVE */}
      <Button
        onClick={handleSave}
        className="mpl-btn-primary mt-6 h-11 px-7 text-sm"
      >
        Simpan Perubahan
      </Button>

      {/* MODAL */}
      <Dialog open={showSuccess} onOpenChange={setShowSuccess}>
        <DialogContent className="max-w-md text-center py-12">
          <div className="flex flex-col items-center gap-5">
            <CheckCircle2 className="w-12 h-12 text-emerald-500" />
            <div className="text-lg font-bold text-gray-900">
              PERUBAHAN BERHASIL
            </div>
            <Button onClick={() => setShowSuccess(false)}>
              Tutup
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}
